import React, { useState, useEffect } from 'react';
import { getSaleReport, getItemWiseReport } from '../services/api';

const fmt = n => `₹${parseFloat(n || 0).toFixed(2)}`;
const payColor = { cash: 'badge-green', card: 'badge-blue', upi: 'badge-purple', mixed: 'badge-yellow' };

export default function Reports() {
  const [tab, setTab] = useState('sale');
  const [saleData, setSaleData] = useState(null);
  const [itemData, setItemData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');

  const fetchReport = async () => {
    setLoading(true);
    const params = {};
    if (dateFrom) params.date_from = dateFrom;
    if (dateTo) params.date_to = dateTo;
    try {
      if (tab === 'sale') {
        const { data } = await getSaleReport(params);
        setSaleData(data);
      } else {
        const { data } = await getItemWiseReport(params);
        setItemData(data);
      }
    } catch {}
    setLoading(false);
  };

  useEffect(() => { fetchReport(); }, [tab]);

  return (
    <div>
      <div className="page-header">
        <h1>📊 Reports</h1>
        <div style={{ display: 'flex', gap: 8 }}>
          <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} style={{ width: 160 }} />
          <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} style={{ width: 160 }} />
          <button className="btn btn-primary" onClick={fetchReport}>Filter</button>
        </div>
      </div>

      {/* Tab buttons */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
        {[{ k: 'sale', label: '🧾 Sale Report' }, { k: 'itemwise', label: '📦 Item-wise Report' }].map(t => (
          <button key={t.k} onClick={() => setTab(t.k)} className="btn" style={{
            background: tab === t.k ? 'var(--accent)' : 'var(--surface)',
            color: tab === t.k ? '#fff' : 'var(--text2)',
            border: `1px solid ${tab === t.k ? 'var(--accent)' : 'var(--border)'}`,
            fontSize: 14, fontWeight: 600
          }}>{t.label}</button>
        ))}
      </div>

      {loading ? <div className="spinner" /> : (
        <>
          {/* Sale Report */}
          {tab === 'sale' && saleData && (
            <>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16, marginBottom: 24 }}>
                {[
                  { label: 'Grand Total', value: fmt(saleData.totals.grand_total), color: 'var(--accent)' },
                  { label: 'Cash Total', value: fmt(saleData.totals.cash_total), color: 'var(--green)' },
                  { label: 'Card Total', value: fmt(saleData.totals.card_total), color: 'var(--blue)' },
                  { label: 'UPI Total', value: fmt(saleData.totals.upi_total), color: 'var(--purple)' },
                ].map(s => (
                  <div key={s.label} className="stat-card">
                    <div className="label">{s.label}</div>
                    <div className="value" style={{ color: s.color }}>{s.value}</div>
                  </div>
                ))}
              </div>
              <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
                <table>
                  <thead><tr><th>Bill No</th><th>Date</th><th>Payment</th><th>Cash</th><th>Card</th><th>Total</th></tr></thead>
                  <tbody>
                    {saleData.bills.map(b => (
                      <tr key={b.id}>
                        <td><span className="badge badge-orange" style={{ fontFamily: 'var(--mono)' }}>{b.bill_number}</span></td>
                        <td style={{ fontSize: 12 }}>{new Date(b.created_at).toLocaleString()}</td>
                        <td><span className={`badge ${payColor[b.payment_type] || 'badge-orange'}`}>{b.payment_type}</span></td>
                        <td style={{ fontFamily: 'var(--mono)' }}>{fmt(b.cash_amount)}</td>
                        <td style={{ fontFamily: 'var(--mono)' }}>{fmt(b.card_amount)}</td>
                        <td style={{ fontWeight: 700, color: 'var(--accent)', fontFamily: 'var(--mono)' }}>{fmt(b.total_amount)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
                {saleData.bills.length === 0 && <div className="empty-state"><div className="icon">📊</div>No sales in this period</div>}
              </div>
            </>
          )}

          {/* Item-wise Report */}
          {tab === 'itemwise' && (
            <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
              <table>
                <thead><tr><th>Product</th><th>Barcode</th><th>MRP</th><th>Qty Sold</th><th>Total Revenue</th></tr></thead>
                <tbody>
                  {itemData.map((item, i) => (
                    <tr key={i}>
                      <td style={{ fontWeight: 600, color: 'var(--text)' }}>{item.product_name}</td>
                      <td><span style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>{item.product_barcode}</span></td>
                      <td style={{ fontFamily: 'var(--mono)' }}>{fmt(item.mrp)}</td>
                      <td><span className="badge badge-blue">{item.quantity_sold}</span></td>
                      <td style={{ fontWeight: 700, color: 'var(--accent)', fontFamily: 'var(--mono)' }}>{fmt(item.total_amount)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {itemData.length === 0 && <div className="empty-state"><div className="icon">📦</div>No item data in this period</div>}
            </div>
          )}
        </>
      )}
    </div>
  );
}
